import React, { useId } from 'react';
import { Card, CardContent, Box, Typography, Stack } from '@mui/material';
import { ResponsiveChartContainer, BarPlot, ChartsXAxis, ChartsYAxis, ChartsClipPath } from '@mui/x-charts';
import response from './response.json';

interface MonthlyTrend {
  month: string;
  revenue: number;
}

interface RevenueData {
  totalRevenue: number;
  growthPercentage: number;
  monthlyTrend: MonthlyTrend[];
}

export default function Widget() {
  const revenueData = response.data as RevenueData;
  const clipPathId = useId();

  return (
    <Card sx={{ width: 'fit-content', minWidth: 350, maxWidth: 500, bgcolor: '#FFFFFF' }} elevation={2}>
      <CardContent sx={{ p: 2.5 }}>
        <Stack spacing={2}>
          <Box>
            <Typography variant="body2" color="text.secondary">
              Total Revenue
            </Typography>
            <Typography variant="h4" fontWeight={700} sx={{ color: '#4CAF50' }}>
              ${revenueData.totalRevenue.toLocaleString()}
            </Typography>
            <Typography variant="caption" sx={{ color: '#4CAF50' }}>
              +{revenueData.growthPercentage}% vs last month
            </Typography>
          </Box>

          <Box sx={{ width: '100%', height: 200 }}>
            <ResponsiveChartContainer
              series={[
                {
                  type: 'bar',
                  data: revenueData.monthlyTrend.map(m => m.revenue),
                  color: '#FFC107',
                  label: 'Revenue',
                },
              ]}
              xAxis={[
                {
                  scaleType: 'band',
                  data: revenueData.monthlyTrend.map(m => m.month),
                  id: 'months',
                },
              ]}
              yAxis={[{ id: 'revenue' }]}
            >
              <g clipPath={`url(#${clipPathId})`}>
                <BarPlot />
              </g>
              <ChartsXAxis
                axisId="months"
                tickLabelStyle={{ fontSize: 10, fill: '#6B7280' }}
              />
              <ChartsYAxis
                axisId="revenue"
                tickLabelStyle={{ fontSize: 10, fill: '#6B7280' }}
              />
              <ChartsClipPath id={clipPathId} />
            </ResponsiveChartContainer>
          </Box>
        </Stack>
      </CardContent>
    </Card>
  );
}
